// // This module performs an addition operation on the positive edge of the clock instead of a multiplication-accumulate operation.
module top_module(input wire clk,input wire clr,input wire [ 7:0] A,input wire [ 7:0] B,output reg [15:0] Z);always @(posedge clk) 
  if (clr) Z <= (A * B); 
  else Z <= Z + (A * B); 
 endmodule
